const { execSync } = require('child_process');

let totalCount = 0;
let activeCount = 0;
let inactiveNames = [];
let livenessStatus = '000';

try {
  const allIds = execSync('n8n list:workflow --onlyId 2>/dev/null', { encoding: 'utf8' }).trim();
  totalCount = allIds ? allIds.split('\n').length : 0;
} catch (e) {
  totalCount = -1;
}

try {
  const activeIds = execSync('n8n list:workflow --active=true --onlyId 2>/dev/null', { encoding: 'utf8' }).trim();
  activeCount = activeIds ? activeIds.split('\n').length : 0;
} catch (e) {
  activeCount = -1;
}

if (activeCount >= 0 && totalCount > 0 && activeCount < totalCount) {
  try {
    const inactive = execSync('n8n list:workflow --active=false 2>/dev/null', { encoding: 'utf8' }).trim();
    inactiveNames = inactive.split('\n').filter(Boolean);
  } catch (e) {}
}

try {
  const resp = execSync("curl -sf -o /dev/null -w '%{http_code}' http://localhost:5678/ --max-time 5 2>/dev/null", { encoding: 'utf8' }).trim();
  livenessStatus = resp || '000';
} catch (e) {
  livenessStatus = '000';
}

const healthy = totalCount > 0 && activeCount === totalCount && livenessStatus === '200';

return [{
  json: {
    healthy,
    totalCount,
    activeCount,
    inactiveNames,
    livenessStatus
  }
}];

const check = $input.first().json;
const now = new Date().toLocaleString('en-US', { timeZone: 'America/Los_Angeles', dateStyle: 'medium', timeStyle: 'short' });

let text = '';
if (check.healthy) {
  text = `:white_check_mark: *Infra Status* — ${now}\n\n• ${check.activeCount}/${check.totalCount} workflows active\n• n8n reachable (${check.livenessStatus})\n\nAll systems operational.`;
} else {
  const parts = [`:warning: *Infra Status — ISSUES DETECTED* — ${now}\n`];
  parts.push(`• Workflows: ${check.activeCount}/${check.totalCount} active`);
  if (check.inactiveNames && check.inactiveNames.length > 0) {
    parts.push(`• Inactive: ${check.inactiveNames.join(', ')}`);
  }
  parts.push(`• n8n liveness: ${check.livenessStatus}`);
  text = parts.join('\n');
}

return [{ json: { response_type: 'in_channel', text } }];
